import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"美国银行","description":"","frontmatter":{"title":"美国银行"},"headers":[],"relativePath":"03_companies/美国银行.md","filePath":"03_companies/美国银行.md"}'),i={name:"03_companies/美国银行.md"};function o(n,a,d,h,s,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="美国银行" tabindex="-1">美国银行 <a class="header-anchor" href="#美国银行" aria-label="Permalink to &quot;美国银行&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 2011年</li><li><strong>持股情况</strong>: <ul><li>2011年：买入50亿美元优先股，附带认股权证可购买7亿股普通股</li><li>2020年：持有11.9%股权</li><li>2021年：持有12.8%股权</li></ul></li><li><strong>行业</strong>: 银行金融服务</li><li><strong>英文名</strong>: Bank of America Corp.</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>2011年在金融危机后的低谷期买入美国银行，投资50亿美元购买优先股，并获得认股权证可购买7亿股普通股。这是巴菲特典型的&quot;危机投资&quot;——在优质银行遭遇困境时出手。</p><p>持股成本146.31亿美元。2020年市值313.06亿美元，2021年增长至459.52亿美元。伯克希尔是美国银行的最大股东之一。</p><h2 id="投资特点" tabindex="-1">投资特点 <a class="header-anchor" href="#投资特点" aria-label="Permalink to &quot;投资特点&quot;">​</a></h2><ul><li>利用优先股获得稳定收益</li><li>认股权证提供上涨潜力</li><li>银行业务规模优势明显</li><li>管理层改革成效显著</li></ul><h2 id="市值变化" tabindex="-1">市值变化 <a class="header-anchor" href="#市值变化" aria-label="Permalink to &quot;市值变化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>持股成本</th><th>市值</th></tr></thead><tbody><tr><td>2020年</td><td>146.31亿美元</td><td>313.06亿美元</td></tr><tr><td>2021年</td><td>-</td><td>459.52亿美元</td></tr></tbody></table><h2 id="投资意义" tabindex="-1">投资意义 <a class="header-anchor" href="#投资意义" aria-label="Permalink to &quot;投资意义&quot;">​</a></h2><p>这是巴菲特金融领域投资的重要组成部分，展示了他在银行股上的专业判断力。美国银行在金融危机后的重组和改革，使其成为美国银行业的领导者之一。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2011, 2020, 2021, 2022</p>',14)])])}const p=t(i,[["render",o]]);export{u as __pageData,p as default};
